#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding pulmonology-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    chief_complaint:text! \
    onset:string! \
    duration:text! \
    severity:string! \
    dyspnoea:string! \
    dyspnoea_onset:string! \
    cough:string! \
    cough_type:string! \
    sputum_production:string! \
    sputum_colour:string! \
    wheeze:string! \
    chest_pain:string! \
    chest_pain_character:string! \
    weight_loss:string! \
    night_sweats:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_spirometry \
    assessment:references \
    spirometry_performed:string! \
    test_date:date \
    fev1_litres:double \
    fev1_predicted_pct:double \
    fvc_litres:double \
    fvc_predicted_pct:double \
    fev1_fvc_ratio:double \
    post_bronchodilator_fev1:double \
    post_bronchodilator_fev1_pct:double \
    bronchodilator_reversibility:string! \
    reversibility_pct:double \
    peak_flow_lmin:int \
    dlco_pct:double \
    test_quality:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_symptom_assessment \
    assessment:references \
    mrc_dyspnoea_grade:int \
    cat_score:int \
    cough_severity:string! \
    sputum_volume:string! \
    wheeze_frequency:string! \
    chest_tightness:string! \
    exercise_tolerance:text! \
    walking_distance_metres:int \
    six_minute_walk_distance:int \
    oxygen_saturation_rest:double \
    oxygen_saturation_exercise:double \
    sleep_disturbance:string! \
    sleep_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_exacerbation_history \
    assessment:references \
    exacerbations_past_year:int \
    hospitalisations_past_year:int \
    icu_admissions_past_year:int \
    intubation_history:string! \
    niv_history:string! \
    oral_steroid_courses_past_year:int \
    antibiotic_courses_past_year:int \
    last_exacerbation_date:date \
    last_exacerbation_trigger:text! \
    seasonal_pattern:string! \
    seasonal_details:text! \
    pneumonia_history:string! \
    pneumonia_count:int \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    inhaler_use:string! \
    inhaler_technique_assessed:string! \
    inhaler_technique_adequate:string! \
    short_acting_bronchodilator:string! \
    saba_frequency:text! \
    long_acting_bronchodilator:string! \
    inhaled_corticosteroid:string! \
    combination_inhaler:string! \
    long_term_oxygen_therapy:string! \
    oxygen_flow_rate_lmin:double \
    oxygen_hours_per_day:int \
    nebuliser_use:string! \
    oral_medications:text! \
    medication_adherence:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    indication:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_allergies \
    assessment:references \
    has_drug_allergies:string! \
    drug_allergy_details:text! \
    has_environmental_allergies:string! \
    environmental_allergy_details:text! \
    atopic_history:string! \
    eczema:string! \
    allergic_rhinitis:string! \
    food_allergies:string! \
    food_allergy_details:text! \
    aspirin_sensitivity:string! \
    latex_allergy:string! \
    allergy_testing_performed:string! \
    allergy_test_results:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_comorbidities \
    assessment:references \
    cardiovascular_disease:string! \
    cardiovascular_details:text! \
    hypertension:string! \
    diabetes:string! \
    diabetes_type:string! \
    osteoporosis:string! \
    anxiety_depression:string! \
    gastro_oesophageal_reflux:string! \
    obstructive_sleep_apnoea:string! \
    lung_cancer:string! \
    pulmonary_hypertension:string! \
    bronchiectasis:string! \
    interstitial_lung_disease:string! \
    renal_impairment:string! \
    anaemia:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_smoking_exposures \
    assessment:references \
    smoking_status:string! \
    pack_years:double \
    cigarettes_per_day:int \
    age_started_smoking:int \
    age_stopped_smoking:int \
    vaping:string! \
    vaping_details:text! \
    cannabis_smoking:string! \
    passive_smoke_exposure:string! \
    occupational_exposures:string! \
    occupational_exposure_details:text! \
    asbestos_exposure:string! \
    silica_exposure:string! \
    coal_dust_exposure:string! \
    biomass_fuel_exposure:string! \
    chemical_exposure:string! \
    chemical_details:text! \
    smoking_cessation_advice:string! \
    cessation_support_offered:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_functional_status \
    assessment:references \
    adl_independence:string! \
    mobility_level:string! \
    aids_used:text! \
    pulmonary_rehabilitation:string! \
    rehab_benefit:string! \
    home_oxygen_assessment:string! \
    ambulatory_oxygen:string! \
    driving_status:string! \
    employment_impact:string! \
    social_isolation:string! \
    carer_support:string! \
    advance_care_planning:string! \
    advance_care_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    gold_stage:string! \
    gold_group:string! \
    fev1_predicted_pct:double \
    symptom_burden:string! \
    exacerbation_risk:string! \
    composite_score:int! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
